;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4, 5, 6]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@barrel
@damage v=&'game.curTarget.addParam("maxLife", 10)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had max HP permanently increased by 10!"'

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] onObjectTrigger
*event_4
;[exp] onObjectTrigger
*event_5
;[exp] onObjectTrigger

@barrel
@damage v=&'game.curTarget.addParam("life", 100)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had HP restored!"'

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] onObjectTrigger

@barrel anime=*barrel_poison
@eval exp='game.curTarget.heat += 10'
@eval exp='game.curTarget.setStatus(o.酩酊, true)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> got drunk!"'

[eventoff]
;-------------------------------------------------------------------------------
*event_6
;[exp] true

@delevent
@wait time=500 cond='WAY != "e"'
@walk turn=e cond='WAY != "e"'
@wait time=500
@fg l=kobold_brown left=225 top=80 b
@fg c=kobold_brown left=375 top=80 b
@fg a=kobold_black left=525 top=80 b
@fgf r=kobold_brown left=675 top=80
[texton]
[name n=Kobold]「What the hell, intruders?!」[k]
Suddenly, some kobolds waiting on the roof attacked![k]
[textoff]
@clf
@monster pos=1 name=コボルド
@monster pos=2 name=コボルド
@monster pos=3 name=コボルド
@monster pos=4 name=コボルド
@monster pos=5 name=コボルド
